INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Operations$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$In high availability, what does an "active-passive" cluster mean?$np1$, $np1$[{"id":"a","text":"Both nodes process traffic simultaneously and share load"},{"id":"b","text":"One node handles traffic while the standby takes over only on failure"},{"id":"c","text":"Neither node processes traffic until manually started"},{"id":"d","text":"Traffic is randomly distributed each second"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$In active-passive HA, the active node serves traffic while the passive node remains on standby and assumes the role only if the active node fails. Active-active shares load across both.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$In high availability, what does an "active-passive" cluster mean?$np1$);
