INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Operations$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$A change to a core router must be made. Which practice MOST reduces operational risk?$np1$, $np1$[{"id":"a","text":"Apply the change during peak hours for faster feedback"},{"id":"b","text":"Follow a documented change-management process with a rollback plan and maintenance window"},{"id":"c","text":"Make the change directly without a ticket to save time"},{"id":"d","text":"Disable logging during the change to reduce noise"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Formal change management—approval, scheduled maintenance window, documented rollback, and post-change verification—reduces risk and provides an audit trail. Logging should stay enabled to capture issues.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A change to a core router must be made. Which practice MOST reduces operational risk?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Operations$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which SNMP version adds authentication and encryption for management traffic?$np1$, $np1$[{"id":"a","text":"SNMPv1"},{"id":"b","text":"SNMPv2c"},{"id":"c","text":"SNMPv3"},{"id":"d","text":"SNMPv2"}]$np1$::jsonb, $np1$["c"]$np1$::jsonb, $np1$SNMPv3 introduces the User-based Security Model with authentication (HMAC) and privacy (encryption). SNMPv1 and SNMPv2c rely on plaintext community strings.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc1157","label":"RFC 1157 — A Simple Network Management Protocol (SNMP)"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which SNMP version adds authentication and encryption for management traffic?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Operations$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which document defines the agreed level of service, uptime, and response targets between a provider and a customer?$np1$, $np1$[{"id":"a","text":"MOU"},{"id":"b","text":"SLA"},{"id":"c","text":"NDA"},{"id":"d","text":"AUP"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$A Service Level Agreement (SLA) specifies measurable service commitments such as uptime percentage and response times. An MOU is a non-binding understanding, an NDA covers confidentiality, and an AUP governs acceptable use.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which document defines the agreed level of service, uptime, and response targets between a provider and a customer?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which security model assumes no implicit trust and verifies every request regardless of network location?$np1$, $np1$[{"id":"a","text":"Perimeter (castle-and-moat) model"},{"id":"b","text":"Zero Trust"},{"id":"c","text":"Open trust model"},{"id":"d","text":"Transitive trust"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Zero Trust (NIST SP 800-207) removes implicit trust based on network location and continuously authenticates and authorizes every request. The traditional perimeter model trusts internal traffic by default.$np1$, $np1$[{"url":"https://csrc.nist.gov/pubs/sp/800/207/final","label":"NIST SP 800-207 — Zero Trust Architecture"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which security model assumes no implicit trust and verifies every request regardless of network location?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which IEEE standard provides port-based network access control, commonly used with RADIUS for wired/wireless authentication?$np1$, $np1$[{"id":"a","text":"802.1Q"},{"id":"b","text":"802.1X"},{"id":"c","text":"802.3af"},{"id":"d","text":"802.11i"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$802.1X provides port-based network access control: a supplicant authenticates to an authenticator (switch/AP), which consults a RADIUS server before opening the port.$np1$, $np1$[{"url":"https://standards.ieee.org/ieee/802.1X/7345/","label":"IEEE 802.1X — Port-Based Network Access Control"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which IEEE standard provides port-based network access control, commonly used with RADIUS for wired/wireless authentication?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$An attacker floods a switch with bogus source MAC addresses to overflow the CAM table. Which mitigation directly counters this?$np1$, $np1$[{"id":"a","text":"DHCP snooping"},{"id":"b","text":"Port security with a MAC limit"},{"id":"c","text":"Dynamic ARP inspection"},{"id":"d","text":"BPDU guard"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Port security limits the number of MAC addresses learned per port and can shut down or restrict the port, directly stopping a CAM (MAC) table flooding attack. The other features address different attacks.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$An attacker floods a switch with bogus source MAC addresses to overflow the CAM table. Which mitigation directly counters this?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which switch feature prevents a rogue DHCP server by allowing DHCP replies only on trusted ports?$np1$, $np1$[{"id":"a","text":"DHCP snooping"},{"id":"b","text":"Port mirroring"},{"id":"c","text":"Storm control"},{"id":"d","text":"Root guard"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$DHCP snooping builds a binding table and permits DHCP server replies (OFFER/ACK) only on trusted ports, blocking rogue DHCP servers on untrusted access ports.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc2131","label":"RFC 2131 — Dynamic Host Configuration Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which switch feature prevents a rogue DHCP server by allowing DHCP replies only on trusted ports?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 3, $np1$MULTI$np1$::"QType", $np1$Select ALL controls that help mitigate a man-in-the-middle ARP spoofing attack.$np1$, $np1$[{"id":"a","text":"Dynamic ARP Inspection (DAI)"},{"id":"b","text":"DHCP snooping (binding table)"},{"id":"c","text":"Disabling all logging"},{"id":"d","text":"Static ARP entries for critical hosts"}]$np1$::jsonb, $np1$["a","b","d"]$np1$::jsonb, $np1$DAI validates ARP packets against the DHCP snooping binding table, and static ARP entries pin critical mappings—both mitigate ARP spoofing. Disabling logging only reduces visibility and helps an attacker.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc826","label":"RFC 826 — Address Resolution Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Select ALL controls that help mitigate a man-in-the-middle ARP spoofing attack.$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which firewall type tracks the state of connections and allows return traffic for established sessions?$np1$, $np1$[{"id":"a","text":"Stateless packet filter"},{"id":"b","text":"Stateful inspection firewall"},{"id":"c","text":"Hub"},{"id":"d","text":"Layer 2 switch"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$A stateful firewall maintains a connection table and automatically permits return traffic that matches an established session, unlike a stateless filter that evaluates each packet in isolation.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which firewall type tracks the state of connections and allows return traffic for established sessions?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 1, $np1$SINGLE$np1$::"QType", $np1$Which wireless security standard introduced Simultaneous Authentication of Equals (SAE) to replace the WPA2 pre-shared key handshake?$np1$, $np1$[{"id":"a","text":"WEP"},{"id":"b","text":"WPA"},{"id":"c","text":"WPA2"},{"id":"d","text":"WPA3"}]$np1$::jsonb, $np1$["d"]$np1$::jsonb, $np1$WPA3-Personal uses SAE (Dragonfly) to resist offline dictionary attacks and provide forward secrecy, replacing the WPA2 4-way PSK handshake. WEP and WPA are deprecated.$np1$, $np1$[{"url":"https://standards.ieee.org/ieee/802.11/7028/","label":"IEEE 802.11 — Wireless LAN"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which wireless security standard introduced Simultaneous Authentication of Equals (SAE) to replace the WPA2 pre-shared key handshake?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Security$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$A company isolates IoT cameras onto their own VLAN with an ACL allowing only the NVR. This BEST illustrates which principle?$np1$, $np1$[{"id":"a","text":"Defense in depth via network segmentation"},{"id":"b","text":"Security through obscurity"},{"id":"c","text":"Single sign-on"},{"id":"d","text":"Geofencing"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$Placing IoT devices on a segmented VLAN with least-privilege ACLs limits lateral movement and the attack surface—an application of network segmentation within defense in depth.$np1$, $np1$[{"url":"https://csrc.nist.gov/pubs/sp/800/207/final","label":"NIST SP 800-207 — Zero Trust Architecture"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A company isolates IoT cameras onto their own VLAN with an ACL allowing only the NVR. This BEST illustrates which principle?$np1$);
