INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which command shows the Layer 3 path and per-hop latency to a destination?$np1$, $np1$[{"id":"a","text":"traceroute / tracert"},{"id":"b","text":"ipconfig"},{"id":"c","text":"route print"},{"id":"d","text":"ping -t"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$traceroute (tracert on Windows) reveals each Layer 3 hop and round-trip time by incrementing the TTL, helping isolate where latency or packet loss occurs along the path.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which command shows the Layer 3 path and per-hop latency to a destination?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$A user can ping by IP address but not by hostname. Which subsystem is the MOST likely cause?$np1$, $np1$[{"id":"a","text":"Default gateway"},{"id":"b","text":"DNS resolution"},{"id":"c","text":"Physical cabling"},{"id":"d","text":"Switch CAM table"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Successful ping by IP confirms Layer 3 connectivity, so the failure to resolve names points to DNS (wrong resolver, unreachable server, or bad record). Cabling/gateway issues would also break IP connectivity.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc1035","label":"RFC 1035 — Domain Names: Implementation and Specification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A user can ping by IP address but not by hostname. Which subsystem is the MOST likely cause?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$A workstation shows an IP address of 169.254.23.7. What does this indicate?$np1$, $np1$[{"id":"a","text":"A static public IP was assigned"},{"id":"b","text":"The host failed to obtain a DHCP lease and self-assigned an APIPA address"},{"id":"c","text":"The host is on the corporate VLAN successfully"},{"id":"d","text":"The DNS server is misconfigured"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$The 169.254.0.0/16 range is APIPA, auto-assigned when a client cannot reach a DHCP server. It indicates a DHCP failure (server down, no relay, or broken link), not a DNS problem.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc2131","label":"RFC 2131 — Dynamic Host Configuration Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A workstation shows an IP address of 169.254.23.7. What does this indicate?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$MULTI$np1$::"QType", $np1$Select ALL plausible causes of intermittent packet loss on a copper Ethernet link.$np1$, $np1$[{"id":"a","text":"Duplex mismatch between switch and host"},{"id":"b","text":"Excessive cable length beyond 100 m / EMI"},{"id":"c","text":"A correctly configured loopback test on an unused port"},{"id":"d","text":"A failing/oversubscribed uplink causing congestion"}]$np1$::jsonb, $np1$["a","b","d"]$np1$::jsonb, $np1$Duplex mismatches, runs exceeding 100 m or near EMI sources, and congested/oversubscribed uplinks all cause intermittent loss. A loopback on an unused port does not affect production traffic.$np1$, $np1$[{"url":"https://standards.ieee.org/ieee/802.3/10422/","label":"IEEE 802.3 — Ethernet"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Select ALL plausible causes of intermittent packet loss on a copper Ethernet link.$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which command displays the local ARP cache mapping IP addresses to MAC addresses?$np1$, $np1$[{"id":"a","text":"arp -a"},{"id":"b","text":"nslookup"},{"id":"c","text":"tracert"},{"id":"d","text":"netstat -r"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$`arp -a` lists the local ARP cache (IP-to-MAC bindings). `netstat -r` shows the routing table, `nslookup` queries DNS, and `tracert` traces the path.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc826","label":"RFC 826 — Address Resolution Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which command displays the local ARP cache mapping IP addresses to MAC addresses?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$Two PCs in the same VLAN/subnet cannot reach each other, but each reaches the gateway. A switch port shows "err-disabled". What is the MOST likely cause?$np1$, $np1$[{"id":"a","text":"DNS misconfiguration"},{"id":"b","text":"Port security or BPDU guard disabled the port after a violation"},{"id":"c","text":"Incorrect default gateway on both PCs"},{"id":"d","text":"The Internet circuit is down"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$An err-disabled port is typically shut down by a security feature (port security violation, BPDU guard, or loop detection). Since the gateway is reachable, DNS and the WAN are not the issue.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Two PCs in the same VLAN/subnet cannot reach each other, but each reaches the gateway. A switch port shows "err-disabled". What is the MOST likely cause?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which tool identifies the specific switch port and cable run a wall jack connects to?$np1$, $np1$[{"id":"a","text":"Toner probe (tone generator/probe)"},{"id":"b","text":"Spectrum analyzer"},{"id":"c","text":"Loopback plug"},{"id":"d","text":"Multimeter"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$A tone generator and inductive probe place a signal on a cable so the technician can trace and identify the matching run/port in a wiring closet. A spectrum analyzer is for RF.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which tool identifies the specific switch port and cable run a wall jack connects to?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$Wi-Fi clients near a microwave oven experience throughput drops on 2.4 GHz. Which tool BEST diagnoses the cause?$np1$, $np1$[{"id":"a","text":"Cable certifier"},{"id":"b","text":"Spectrum analyzer"},{"id":"c","text":"Protocol analyzer for TCP"},{"id":"d","text":"Multimeter"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$A spectrum analyzer visualizes RF energy and non-Wi-Fi interference (e.g., a microwave oven on 2.4 GHz). A cable certifier and multimeter test copper; a TCP analyzer does not see RF.$np1$, $np1$[{"url":"https://standards.ieee.org/ieee/802.11/7028/","label":"IEEE 802.11 — Wireless LAN"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Wi-Fi clients near a microwave oven experience throughput drops on 2.4 GHz. Which tool BEST diagnoses the cause?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$A fiber link is down and the optical power meter reads far below the receiver sensitivity. Which is the MOST likely cause?$np1$, $np1$[{"id":"a","text":"Duplex mismatch"},{"id":"b","text":"Excessive attenuation from a dirty/damaged connector or bend"},{"id":"c","text":"Incorrect VLAN assignment"},{"id":"d","text":"DHCP scope exhaustion"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Very low received optical power indicates excessive attenuation—commonly a dirty or damaged connector, macrobend, or wrong fiber type. VLAN/DHCP issues do not change optical power.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A fiber link is down and the optical power meter reads far below the receiver sensitivity. Which is the MOST likely cause?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$Which command on Windows releases and renews a DHCP-assigned IPv4 address?$np1$, $np1$[{"id":"a","text":"ipconfig /release then ipconfig /renew"},{"id":"b","text":"arp -d"},{"id":"c","text":"route delete"},{"id":"d","text":"netsh winsock reset"}]$np1$::jsonb, $np1$["a"]$np1$::jsonb, $np1$`ipconfig /release` drops the current lease and `ipconfig /renew` requests a new one from the DHCP server—useful when a client is stuck on a stale or APIPA address.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc2131","label":"RFC 2131 — Dynamic Host Configuration Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Which command on Windows releases and renews a DHCP-assigned IPv4 address?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$Users report a website is "slow" only for large downloads, while small requests are fast. Which metric is the MOST relevant to investigate first?$np1$, $np1$[{"id":"a","text":"DNS TTL"},{"id":"b","text":"Throughput/bandwidth and link congestion"},{"id":"c","text":"MAC address aging timer"},{"id":"d","text":"STP root bridge ID"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$Small requests being fast but large transfers slow points to limited throughput or congestion (saturated uplink, QoS policing, or bandwidth shaping), not DNS or Layer 2 timers.$np1$, $np1$[{"url":"https://www.comptia.org/certifications/network","label":"CompTIA — Network+ (N10-009) Certification"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$Users report a website is "slow" only for large downloads, while small requests are fast. Which metric is the MOST relevant to investigate first?$np1$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 2, $np1$SINGLE$np1$::"QType", $np1$After replacing a SOHO router, internal hosts get addresses but cannot reach the Internet, though the router itself can. What should you check FIRST?$np1$, $np1$[{"id":"a","text":"The host file on each PC"},{"id":"b","text":"NAT/PAT and the WAN/default route configuration on the new router"},{"id":"c","text":"The switch MAC aging timer"},{"id":"d","text":"The wireless channel width"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$If the router reaches the Internet but LAN hosts do not, outbound NAT/PAT or the LAN-to-WAN routing is the likely gap. Per-PC host files and Layer 2 timers would not selectively block all outbound traffic.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc3022","label":"RFC 3022 — Traditional IP Network Address Translator (NAT)"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$After replacing a SOHO router, internal hosts get addresses but cannot reach the Internet, though the router itself can. What should you check FIRST?$np1$);
