INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $np1$Network Troubleshooting$np1$, 3, $np1$SINGLE$np1$::"QType", $np1$A captured packet trace shows many TCP retransmissions and duplicate ACKs between two hosts. What does this MOST likely indicate?$np1$, $np1$[{"id":"a","text":"Healthy traffic with no issues"},{"id":"b","text":"Packet loss or congestion somewhere along the path"},{"id":"c","text":"A DNS misconfiguration"},{"id":"d","text":"An incorrect subnet mask on the analyzer"}]$np1$::jsonb, $np1$["b"]$np1$::jsonb, $np1$TCP retransmissions and duplicate ACKs are classic indicators of packet loss or congestion on the path, prompting the sender to resend segments. DNS or analyzer masks do not produce this TCP behavior.$np1$, $np1$[{"url":"https://www.rfc-editor.org/rfc/rfc9293","label":"RFC 9293 — Transmission Control Protocol"}]$np1$::jsonb, $np1$PUBLISHED$np1$::"QStatus", $np1$manual:networkplus-seed$np1$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $np1$comptia-network-plus-p1$np1$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $np1$A captured packet trace shows many TCP retransmissions and duplicate ACKs between two hosts. What does this MOST likely indicate?$np1$);
